SELECT COUNT(video_id) AS cat_videos_count
FROM video_tags
WHERE tag_id = (SELECT tag_id FROM tags WHERE tag_name = 'cats');

SELECT COUNT(video_id) AS num_videos
FROM video_tags
WHERE tag_id = 0;

SELECT COUNT(video_id) AS video_count
FROM video_categories
WHERE category_id = 0;

SELECT COUNT(subscription_id) AS subscription_count
FROM subscriptions
WHERE user_id = 0;

